#include<bits/stdc++.h>
using namespace std;
long long fib[50],x;
int t;
int main()
{
    fib[1]=fib[2]=1;
    for(int i=3;fib[i-1]<1000000000;i++)
    {
		fib[i]=fib[i-1]+fib[i-2];
	}
    cin>>t;
    for(int i=1;i<=t;i++)
    {
        cin>>x;
        cout<<"2 "<<x<<'\n';
        for(int j=3;x>=fib[j];j++)
        {
            if((x-fib[j-2])%fib[j-1]==0) cout<<j<<' '<<(x-fib[j-2])/fib[j-1]<<'\n';
        }
    }
    return 0;
}
